import React, { useEffect } from 'react';
import { useSelector, useDispatch } from 'react-redux';
import { useNavigate } from 'react-router-dom';
import { fetchMyPosts } from '../redux/thunks/postThunks';
import { fetchFriendCount } from '../redux/thunks/friendThunks';
import { NODE_API } from '../api/config';
import PostCard from '../components/posts/PostCard';
import './Profile.css';

const Profile = () => {
  const { user } = useSelector((state) => state.auth);
  const { myPosts, hasMoreMine } = useSelector((state) => state.posts);
  const { friendCount } = useSelector((state) => state.friends);
  const dispatch = useDispatch();
  const navigate = useNavigate();

  useEffect(() => {
    dispatch(fetchMyPosts({ skip: 0, limit: 20 }));
    if (user?._id) dispatch(fetchFriendCount({ userId: user._id }));
  }, [dispatch, user?._id]);

  const getImageUrl = (path) => {
    if (!path) return null;
    if (path.startsWith('http')) return path;
    return `${NODE_API}/${path}`;
  };

  const bannerUrl = getImageUrl(user?.bannerURL?.original || user?.bannerURL);
  const avatarUrl = getImageUrl(user?.imageURL?.original || user?.imageURL?.thumbnail || user?.imageURL);

  const handleLoadMore = () => {
    dispatch(fetchMyPosts({ skip: myPosts.length, limit: 20 }));
  };

  return (
    <div className="profile-page">
      {/* Banner */}
      <div
        className="profile-banner"
        style={bannerUrl ? { backgroundImage: `url(${bannerUrl})` } : {}}
      >
        {!bannerUrl && <div className="profile-banner-gradient" />}
      </div>

      {/* Avatar + Info */}
      <div className="profile-info-section">
        <div className="profile-avatar-wrap">
          {avatarUrl ? (
            <img src={avatarUrl} alt="Profile" className="profile-avatar" />
          ) : (
            <div className="profile-avatar-placeholder">
              {(user?.firstName || 'U')[0].toUpperCase()}
            </div>
          )}
        </div>

        <h1 className="profile-name">
          {user?.firstName} {user?.lastName}
        </h1>
        {user?.email && <p className="profile-email">{user.email}</p>}
        {(user?.city || user?.state || user?.country) && (
          <p className="profile-location">
            📍 {[user.city, user.state, user.country].filter(Boolean).join(', ')}
          </p>
        )}
        {user?.about && <p className="profile-bio">{user.about}</p>}

        <div className="profile-stats" onClick={() => navigate('/friends')}>
          <span className="profile-stat-count">{friendCount}</span>
          <span className="profile-stat-label">Friends</span>
        </div>

        <button className="profile-edit-btn" onClick={() => navigate('/profile/edit')}>
          Edit Profile
        </button>
      </div>

      {/* Posts */}
      <div className="profile-posts-section">
        <h3 className="profile-posts-title">My Posts ({myPosts.length})</h3>

        {myPosts.length === 0 && (
          <div className="profile-posts-empty">
            <p>No posts yet</p>
            <button className="profile-create-btn" onClick={() => navigate('/create-post')}>
              Create Your First Post
            </button>
          </div>
        )}

        {myPosts.map((post) => (
          <PostCard key={post._id} post={post} showDelete />
        ))}

        {hasMoreMine && myPosts.length > 0 && (
          <button className="home-load-more" onClick={handleLoadMore}>
            Load More
          </button>
        )}
      </div>
    </div>
  );
};

export default Profile;
